package crdt

import (
	"reflect"
	"testing"
)

type ewFlagSnapshot struct {
	dots     map[string]uint64
	counters map[string]uint64
}

func TestEWFlagMergeCausalSemantics(t *testing.T) {
	tests := []struct {
		name      string
		setup     func() (*EWFlag, *EWFlag)
		wantValue bool
		wantDots  int
	}{
		{
			name: "concurrent enable wins over disable with empty dot set",
			setup: func() (*EWFlag, *EWFlag) {
				enabled := NewEWFlag()
				enabled.Enable("node-a")

				disabled := NewEWFlag()
				disabled.Disable()

				return enabled, disabled
			},
			wantValue: true,
			wantDots:  1,
		},
		{
			name: "observed disable clears enable",
			setup: func() (*EWFlag, *EWFlag) {
				enabled := NewEWFlag()
				enabled.Enable("node-a")

				disabled := NewEWFlag()
				disabled.Merge(enabled)
				disabled.Disable()

				return enabled, disabled
			},
			wantValue: false,
			wantDots:  0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			left, right := tt.setup()

			t.Run("left merges right", func(t *testing.T) {
				merged := cloneEWFlag(left)
				merged.Merge(right)
				assertEWFlagState(t, merged, tt.wantValue, tt.wantDots)
			})

			t.Run("right merges left", func(t *testing.T) {
				merged := cloneEWFlag(right)
				merged.Merge(left)
				assertEWFlagState(t, merged, tt.wantValue, tt.wantDots)
			})
		})
	}
}

func TestEWFlagMergeRepeatedMergesAreIdempotentAndCommutative(t *testing.T) {
	tests := []struct {
		name  string
		setup func() (*EWFlag, *EWFlag)
	}{
		{
			name: "concurrent enable and disable",
			setup: func() (*EWFlag, *EWFlag) {
				enabled := NewEWFlag()
				enabled.Enable("node-a")

				disabled := NewEWFlag()
				disabled.Disable()

				return enabled, disabled
			},
		},
		{
			name: "observed enable then disable",
			setup: func() (*EWFlag, *EWFlag) {
				enabled := NewEWFlag()
				enabled.Enable("node-a")

				disabled := NewEWFlag()
				disabled.Merge(enabled)
				disabled.Disable()

				return enabled, disabled
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			left, right := tt.setup()

			leftMerged := cloneEWFlag(left)
			leftMerged.Merge(right)
			once := snapshotEWFlag(leftMerged)
			leftMerged.Merge(right)
			twice := snapshotEWFlag(leftMerged)
			if !reflect.DeepEqual(once, twice) {
				t.Fatalf("merge is not idempotent: once=%+v twice=%+v", once, twice)
			}

			rightMerged := cloneEWFlag(right)
			rightMerged.Merge(left)
			reverse := snapshotEWFlag(rightMerged)
			if !reflect.DeepEqual(once, reverse) {
				t.Fatalf("merge is not commutative: left/right=%+v right/left=%+v", once, reverse)
			}
		})
	}
}

func assertEWFlagState(t *testing.T, flag *EWFlag, wantValue bool, wantDots int) {
	t.Helper()

	if got := flag.Value(); got != wantValue {
		t.Fatalf("Value() = %v, want %v", got, wantValue)
	}
	if got := flag.DotCount(); got != wantDots {
		t.Fatalf("DotCount() = %d, want %d", got, wantDots)
	}
}

func cloneEWFlag(flag *EWFlag) *EWFlag {
	flag.mu.RLock()
	defer flag.mu.RUnlock()

	return &EWFlag{
		dots:     cloneUint64Map(flag.dots),
		counters: cloneUint64Map(flag.counters),
	}
